export function replaceRedditLinks(e){var t=e.replace(/href="\/u\/([^"]+)"/g,'href="user.html?u=$1"').replace(/href="\/r\/([^"]+)"/g,'href="subreddit.html?r=$1"').replace(/(href=\"https:\/\/(old.|www.|)reddit\.com\/r\/[^\/]+\/comments\/[^"]+)(\?[^"]+)?/g,function(e,t,r){return'class="comment-icon icon" href="comments.html?url='+encodeURIComponent(t).replace(/href%3D%22/g,"")}).replace(/(href=\"https:\/\/reddit\.com\/r\/[^\/]+\/comments\/[^"]+)(\?[^"]+)?/g,function(e,t,r){return'class="comment-icon icon" comments.html?url='+encodeURIComponent(t+(r||""))});return console.log("replaceRedditLinks  before",t),t=t.replace(/<a href="https:\/\/giphy\.com\/gifs\/([^"]+)"[^>]*>.*?<\/a>/g,(e,t)=>`\n            <div style="width:100%;height:0;padding-bottom:56%;position:relative;">\n                <iframe src="https://giphy.com/embed/${t}" width="100%" height="100%" style="position:absolute" frameBorder="0" class="giphy-embed" allowFullScreen></iframe>\n            </div>`),console.log("replaceRedditLinks  after",t),t}export function htmlDecode(e){return(new DOMParser).parseFromString(e,"text/html").body.textContent}